def solve():
    q = int(input())
    queries = []
    for _ in range(q):
        line = input().split()
        if line[0] == '1':
            queries.append((1, int(line[1])))
        else:
            queries.append((2, int(line[1]), int(line[2])))

    current_map = {}
    result = []

    for i in range(q - 1, -1, -1):
        query = queries[i]
        if query[0] == 1:
            x = query[1]
            result.append(current_map.get(x, x))
        else:
            x, y = query[1], query[2]
            current_map[x] = current_map.get(y, y)

    result.reverse()
    print(*result)

solve()

